/**
 * SMS notification channel — sends SMS notifications in response to events.
 *
 * Subscribes to the EventBus following the same pattern as NotificationService.
 * Handles order:created and order:status-changed events via SMS.
 *
 * Depends on:
 * - EventBus (event system) for receiving events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface SmsMessage {
  id: string;
  phoneNumber: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateSmsId(): string {
  return `sms-${String(nextId++).padStart(4, '0')}`;
}

export function resetSmsIdCounter(): void {
  nextId = 1;
}

export class SmsNotificationService {
  private logger = new Logger('SmsNotificationService');
  private messages: SmsMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending SMS for order ${event.order.id}`);

    const itemCount = event.order.items.reduce((sum, item) => sum + item.quantity, 0);

    this.sendSms({
      phoneNumber: event.user.id,
      body: `Order ${event.order.id} confirmed: ${itemCount} item(s), total $${event.order.total.toFixed(2)}.`,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(`Sending SMS status update for order ${event.order.id}`);

    this.sendSms({
      phoneNumber: event.order.userId,
      body: `Order ${event.order.id} status: ${event.newStatus}.`,
    });
  }

  private sendSms(params: { phoneNumber: string; body: string }): void {
    const message: SmsMessage = {
      id: generateSmsId(),
      phoneNumber: params.phoneNumber,
      body: params.body,
      sentAt: new Date(),
    };
    this.messages.push(message);
    this.logger.info(`SMS sent: ${message.id} to ${params.phoneNumber}`);
  }

  getMessages(): SmsMessage[] {
    return [...this.messages];
  }

  getMessagesForPhone(phoneNumber: string): SmsMessage[] {
    return this.messages.filter((m) => m.phoneNumber === phoneNumber);
  }

  getMessageCount(): number {
    return this.messages.length;
  }

  clearMessages(): void {
    this.messages = [];
  }
}

/**
 * Webhook notification channel — dispatches webhook payloads in response to events.
 *
 * Subscribes to the EventBus following the same pattern as NotificationService.
 * Handles order:created and order:status-changed events by recording webhook deliveries.
 *
 * Depends on:
 * - EventBus (event system) for receiving events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookDelivery {
  id: string;
  url: string;
  eventType: string;
  payload: Record<string, unknown>;
  deliveredAt: Date;
}

let nextId = 1;

function generateWebhookId(): string {
  return `wh-${String(nextId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextId = 1;
}

export class WebhookNotificationService {
  private logger = new Logger('WebhookNotificationService');
  private deliveries: WebhookDelivery[] = [];

  constructor(
    private eventBus: EventBus,
    private webhookUrl: string,
  ) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending webhook for order ${event.order.id}`);

    this.deliverWebhook('order:created', {
      orderId: event.order.id,
      userId: event.user.id,
      items: event.order.items.map((item) => ({
        productId: item.productId,
        name: item.name,
        quantity: item.quantity,
      })),
      total: event.order.total,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(`Sending webhook for status change on order ${event.order.id}`);

    this.deliverWebhook('order:status-changed', {
      orderId: event.order.id,
      previousStatus: event.previousStatus,
      newStatus: event.newStatus,
    });
  }

  private deliverWebhook(eventType: string, payload: Record<string, unknown>): void {
    const delivery: WebhookDelivery = {
      id: generateWebhookId(),
      url: this.webhookUrl,
      eventType,
      payload,
      deliveredAt: new Date(),
    };
    this.deliveries.push(delivery);
    this.logger.info(`Webhook delivered: ${delivery.id} to ${this.webhookUrl}`);
  }

  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  getDeliveriesByEventType(eventType: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.eventType === eventType);
  }

  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }
}

